create table if not exists public.transportation_hubs (hub_id text primary key, hub_type text not null, code text, destination_id text, timezone text not null, arrival_buffer integer not null default 90, departure_buffer integer not null default 180, map_urls jsonb not null default '{}'::jsonb, guide_ids jsonb not null default '[]'::jsonb);
create table if not exists public.trip_flights (flight_id uuid primary key default gen_random_uuid(), trip_id uuid not null references public.trips(id) on delete cascade, flight_type text not null, airline text not null, flight_number text not null, departure_hub_id text references public.transportation_hubs(hub_id), arrival_hub_id text references public.transportation_hubs(hub_id), departure_at timestamptz not null, arrival_at timestamptz not null, seat text, booking_reference text, created_at timestamptz not null default now());
alter table public.trip_flights enable row level security;
create policy "trip owners manage flights" on public.trip_flights for all using (exists (select 1 from public.trips where trips.id=trip_flights.trip_id and trips.user_id=auth.uid())) with check (exists (select 1 from public.trips where trips.id=trip_flights.trip_id and trips.user_id=auth.uid()));
